import{bV as s,aL as a,u as p,G as l}from"./chunks/framework.D_inzUUb.js";const _=JSON.parse('{"title":"自动角色生成","description":"","frontmatter":{},"headers":[],"relativePath":"mumuainovel/自动角色生成.md","filePath":"mumuainovel/自动角色生成.md","lastUpdated":1777605538000}'),e={name:"mumuainovel/自动角色生成.md"};function t(i,n,c,o,u,q){return a(),p("div",null,[...n[0]||(n[0]=[l(`<h1 id="自动角色生成" tabindex="-1">自动角色生成 <a class="header-anchor" href="#自动角色生成" aria-label="Permalink to &quot;自动角色生成&quot;">​</a></h1><blockquote><p>模板键: <code>AUTO_CHARACTER_GENERATION</code> 分类: 自动角色引入 描述: 根据剧情需求自动生成新角色的完整设定 参数: [&quot;title&quot;, &quot;genre&quot;, &quot;theme&quot;, &quot;time_period&quot;, &quot;location&quot;, &quot;atmosphere&quot;, &quot;rules&quot;, &quot;existing_characters&quot;, &quot;plot_context&quot;, &quot;character_specification&quot;, &quot;mcp_references&quot;]</p></blockquote><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;system&gt;</span></span>
<span class="line"><span>你是专业的角色设定师，擅长根据剧情需求创建立体丰满的角色，并为角色构建推动剧情的关系网络。</span></span>
<span class="line"><span>&lt;/system&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;task&gt;</span></span>
<span class="line"><span>【生成任务】</span></span>
<span class="line"><span>为小说生成新角色的完整设定，包括基本信息、性格背景、关系网络和职业信息。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【核心要求】</span></span>
<span class="line"><span>1. 角色必须嵌入一个&quot;冲突网络&quot;，至少包含：</span></span>
<span class="line"><span>   - 1条合作关系</span></span>
<span class="line"><span>   - 1条潜在冲突或对立关系</span></span>
<span class="line"><span>2. 角色必须具备&quot;改变剧情走向的能力&quot;</span></span>
<span class="line"><span>3. 必须分析新角色与已有角色的关系，至少建立1-3个有意义的关系</span></span>
<span class="line"><span>&lt;/task&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;project priority=&quot;P1&quot;&gt;</span></span>
<span class="line"><span>【项目信息】</span></span>
<span class="line"><span>书名：{title}</span></span>
<span class="line"><span>类型：{genre}</span></span>
<span class="line"><span>主题：{theme}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【世界观】</span></span>
<span class="line"><span>时间背景：{time_period}</span></span>
<span class="line"><span>地理位置：{location}</span></span>
<span class="line"><span>氛围基调：{atmosphere}</span></span>
<span class="line"><span>世界规则：{rules}</span></span>
<span class="line"><span>&lt;/project&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;context priority=&quot;P0&quot;&gt;</span></span>
<span class="line"><span>【已有角色】</span></span>
<span class="line"><span>{existing_characters}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【剧情上下文】</span></span>
<span class="line"><span>{plot_context}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【角色规格要求】</span></span>
<span class="line"><span>{character_specification}</span></span>
<span class="line"><span>&lt;/context&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;mcp_context priority=&quot;P2&quot;&gt;</span></span>
<span class="line"><span>【MCP工具参考】</span></span>
<span class="line"><span>{mcp_references}</span></span>
<span class="line"><span>&lt;/mcp_context&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;requirements priority=&quot;P0&quot;&gt;</span></span>
<span class="line"><span>【角色深度要求 - 必须全部满足】</span></span>
<span class="line"><span>✅ 每个角色必须有明确目标（goal字段）</span></span>
<span class="line"><span>✅ 每个角色必须有外部冲突（external_conflict字段）</span></span>
<span class="line"><span>✅ 每个角色必须有压力触发点（pressure_point字段）</span></span>
<span class="line"><span>✅ 这些字段直接影响剧情推动力，不可省略</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【基础要求】</span></span>
<span class="line"><span>1. 角色必须符合剧情需求和世界观设定</span></span>
<span class="line"><span>2. 必须分析新角色与已有角色的关系，至少建立1-3个有意义的关系</span></span>
<span class="line"><span>3. 性格、背景要有深度和独特性</span></span>
<span class="line"><span>4. 外貌描写要具体生动</span></span>
<span class="line"><span>5. 特长和能力要符合角色定位</span></span>
<span class="line"><span>6. 如果【已有角色】中包含职业列表，必须为角色设定职业</span></span>
<span class="line"><span>业</span></span>
<span class="line"><span></span></span>
<span class="line"><span></span></span>
<span class="line"><span>【关系建立指导】</span></span>
<span class="line"><span>- 仔细审视【已有角色】列表，思考新角色与哪些现有角色有联系</span></span>
<span class="line"><span>- 根据剧情需求，建立合理的角色关系</span></span>
<span class="line"><span>- 每个关系都要有明确的类型、亲密度和描述</span></span>
<span class="line"><span>- 关系应该服务于剧情发展</span></span>
<span class="line"><span>- 至少包含1条合作/友好关系和1条对立/冲突关系</span></span>
<span class="line"><span>- 如果新角色是组织成员，记得填写organization_memberships</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【角色功能定位】</span></span>
<span class="line"><span>角色应属于以下之一（在role_type中体现）：</span></span>
<span class="line"><span>- 推动者（protagonist）：主动推进主线</span></span>
<span class="line"><span>- 阻碍者（antagonist）：制造困难或对立</span></span>
<span class="line"><span>- 变数者（supporting）：行为不可预测，改变局势</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【职业信息要求】</span></span>
<span class="line"><span>如果【已有角色】部分包含&quot;可用主职业列表&quot;或&quot;可用副职业列表&quot;：</span></span>
<span class="line"><span>- 仔细查看可用的主职业和副职业列表</span></span>
<span class="line"><span>- 根据角色的背景、能力、故事定位，选择最合适的职业</span></span>
<span class="line"><span>- 主职业：从&quot;可用主职业列表&quot;中选择一个，填写职业名称</span></span>
<span class="line"><span>- 主职业阶段：根据职业的阶段信息和角色实力，设定合理的当前阶段</span></span>
<span class="line"><span>- 副职业：可选择0-2个副职业</span></span>
<span class="line"><span>- ⚠️ 重要：必须填写职业的名称而非ID</span></span>
<span class="line"><span>&lt;/requirements&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;output priority=&quot;P0&quot;&gt;</span></span>
<span class="line"><span>【输出格式】</span></span>
<span class="line"><span>返回纯JSON对象：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>{{</span></span>
<span class="line"><span>  &quot;name&quot;: &quot;角色姓名&quot;,</span></span>
<span class="line"><span>  &quot;age&quot;: 25,</span></span>
<span class="line"><span>  &quot;gender&quot;: &quot;男/女/其他&quot;,</span></span>
<span class="line"><span>  &quot;role_type&quot;: &quot;protagonist/supporting/antagonist&quot;,</span></span>
<span class="line"><span>  &quot;personality&quot;: &quot;性格特点（100-200字）：核心性格、优缺点、特殊习惯&quot;,</span></span>
<span class="line"><span>  &quot;background&quot;: &quot;背景故事（100-200字）：家庭背景、成长经历、重要转折&quot;,</span></span>
<span class="line"><span>  &quot;appearance&quot;: &quot;外貌描述（50-100字）：身高、体型、面容、着装风格&quot;,</span></span>
<span class="line"><span>  &quot;traits&quot;: [&quot;特长1&quot;, &quot;特长2&quot;, &quot;特长3&quot;],</span></span>
<span class="line"><span>  &quot;goal&quot;: &quot;角色的核心目标（一句话）&quot;,</span></span>
<span class="line"><span>  &quot;external_conflict&quot;: &quot;阻碍其目标的人或势力&quot;,</span></span>
<span class="line"><span>  &quot;pressure_point&quot;: &quot;可能让其改变立场的触发点&quot;,</span></span>
<span class="line"><span>  </span></span>
<span class="line"><span>  &quot;relationships&quot;: [</span></span>
<span class="line"><span>    {{</span></span>
<span class="line"><span>      &quot;target_character_name&quot;: &quot;已存在的角色名称&quot;,</span></span>
<span class="line"><span>      &quot;relationship_type&quot;: &quot;关系类型&quot;,</span></span>
<span class="line"><span>      &quot;intimacy_level&quot;: 75,</span></span>
<span class="line"><span>      &quot;description&quot;: &quot;关系的具体描述&quot;,</span></span>
<span class="line"><span>      &quot;status&quot;: &quot;active&quot;</span></span>
<span class="line"><span>    }}</span></span>
<span class="line"><span>  ],</span></span>
<span class="line"><span>  &quot;organization_memberships&quot;: [</span></span>
<span class="line"><span>    {{</span></span>
<span class="line"><span>      &quot;organization_name&quot;: &quot;已存在的组织名称&quot;,</span></span>
<span class="line"><span>      &quot;position&quot;: &quot;职位&quot;,</span></span>
<span class="line"><span>      &quot;rank&quot;: 5,</span></span>
<span class="line"><span>      &quot;loyalty&quot;: 80</span></span>
<span class="line"><span>    }}</span></span>
<span class="line"><span>  ],</span></span>
<span class="line"><span>  </span></span>
<span class="line"><span>  &quot;career_info&quot;: {{</span></span>
<span class="line"><span>    &quot;main_career_name&quot;: &quot;从可用主职业列表中选择的职业名称&quot;,</span></span>
<span class="line"><span>    &quot;main_career_stage&quot;: 5,</span></span>
<span class="line"><span>    &quot;sub_careers&quot;: [</span></span>
<span class="line"><span>      {{</span></span>
<span class="line"><span>        &quot;career_name&quot;: &quot;从可用副职业列表中选择的职业名称&quot;,</span></span>
<span class="line"><span>        &quot;stage&quot;: 3</span></span>
<span class="line"><span>      }}</span></span>
<span class="line"><span>    ]</span></span>
<span class="line"><span>  }}</span></span>
<span class="line"><span>}}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【关系类型参考】</span></span>
<span class="line"><span>- 家族：父亲、母亲、兄弟、姐妹、子女、配偶、恋人</span></span>
<span class="line"><span>- 社交：师父、徒弟、朋友、同学、同事、邻居、知己</span></span>
<span class="line"><span>- 职业：上司、下属、合作伙伴</span></span>
<span class="line"><span>- 敌对：敌人、仇人、竞争对手、宿敌</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【数值范围】</span></span>
<span class="line"><span>- intimacy_level：-100到100（负值表示敌对）</span></span>
<span class="line"><span>- loyalty：0到100</span></span>
<span class="line"><span>- rank：0到10</span></span>
<span class="line"><span>&lt;/output&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;constraints&gt;</span></span>
<span class="line"><span>【必须遵守】</span></span>
<span class="line"><span>✅ 符合剧情需求和世界观设定</span></span>
<span class="line"><span>✅ 性格、背景要有深度和独特性</span></span>
<span class="line"><span>✅ relationships数组必填：至少1-3个关系</span></span>
<span class="line"><span>✅ 关系必须包含冲突性，禁止全是和谐关系</span></span>
<span class="line"><span>✅ target_character_name必须精确匹配【已有角色】</span></span>
<span class="line"><span>✅ organization_memberships只能引用已存在的组织</span></span>
<span class="line"><span>✅ 职业选择必须从可用列表中选择</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【角色深度要求】</span></span>
<span class="line"><span>✅ goal字段必填：角色的核心目标</span></span>
<span class="line"><span>✅ external_conflict字段必填：外部冲突来源</span></span>
<span class="line"><span>✅ pressure_point字段必填：压力触发点</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【格式约束】</span></span>
<span class="line"><span>✅ 纯JSON对象输出，无markdown标记</span></span>
<span class="line"><span>✅ 内容描述中严禁使用特殊符号（引号、方括号、书名号等）</span></span>
<span class="line"><span>✅ 专有名词直接书写，不使用符号包裹</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【禁止事项】</span></span>
<span class="line"><span>❌ 输出markdown标记或代码块</span></span>
<span class="line"><span>❌ 在描述中使用特殊符号</span></span>
<span class="line"><span>❌ 引用不存在的角色或组织</span></span>
<span class="line"><span>❌ 使用职业ID而非职业名称</span></span>
<span class="line"><span>❌ 生成&quot;没有冲突的关系&quot;</span></span>
<span class="line"><span>❌ 脸谱化的角色设定</span></span>
<span class="line"><span>&lt;/constraints&gt;</span></span></code></pre></div>`,3)])])}const m=s(e,[["render",t]]);export{_ as __pageData,m as default};
